+        }
+        let test_neighbours = res.unwrap();
+        debug!(
+            "First 2 neighbours  for first test {:?} {:?}  ",
+            test_neighbours.get((0, 0)).unwrap(),
+            test_neighbours.get((0, 1)).unwrap()
+        );
+        println!("\n 10 first neighbours for first vector : ");
