+            searching: false,
+            datamap_opt: true, // set datamap_opt to true
+        };
+        //
+        debug!("load_hnsw completed");
+        let elapsed_t = start_t.elapsed().unwrap().as_secs() as f32;
+        info!("reload_hnsw : elapsed system time(s) {}", elapsed_t);
+        Ok(hnsw)
+    } // end of load_hnsw
+
